def f(n: int) -> int:
    """Return the number of prime numbers strictly less than n (n ≤ 10 000)."""
    if n <= 2:
        return 0

    limit = max(n, 2)          # ensure at least 2 for the sieve
    sieve = bytearray(b'\x01') * limit
    sieve[0:2] = b'\x00\x00'   # 0 and 1 are not prime

    for p in range(2, int(limit**0.5) + 1):
        if sieve[p]:
            step = p
            start = p * p
            sieve[start:limit:step] = b'\x00' * ((limit - start - 1) // step + 1)

    # Count primes strictly less than n
    return sum(sieve[:n])
