def f(expr: str) -> int:
    """Evaluate an arithmetic expression containing non‑negative integers,
    '+', '-', '*', and parentheses.  Operators respect the usual precedence:
    '*' before '+'/'-'.  Whitespace is ignored.
    """
    i = 0
    n = len(expr)

    def skip_spaces():
        nonlocal i
        while i < n and expr[i].isspace():
            i += 1

    def parse_number() -> int:
        nonlocal i
        skip_spaces()
        start = i
        while i < n and expr[i].isdigit():
            i += 1
        if start == i:                     # no digits found
            raise ValueError("Expected number at position %d" % start)
        return int(expr[start:i])

    def parse_factor() -> int:
        nonlocal i
        skip_spaces()
        if i < n and expr[i] == '(':
            i += 1                         # consume '('
            val = parse_expr()
            skip_spaces()
            if i >= n or expr[i] != ')':
                raise ValueError("Missing closing parenthesis")
            i += 1                         # consume ')'
            return val
        return parse_number()

    def parse_term() -> int:
        nonlocal i
        val = parse_factor()
        while True:
            skip_spaces()
            if i < n and expr[i] == '*':
                i += 1                     # consume '*'
                val *= parse_factor()
            else:
                break
        return val

    def parse_expr() -> int:
        nonlocal i
        val = parse_term()
        while True:
            skip_spaces()
            if i < n and expr[i] in '+-':
                op = expr[i]
                i += 1                     # consume operator
                right = parse_term()
                if op == '+':
                    val += right
                else:
                    val -= right
            else:
                break
        return val

    result = parse_expr()
    skip_spaces()
    if i != n:
        raise ValueError("Unexpected characters at end of expression")
    return result
