def f(lst):
    import bisect
    tails = []                     # tails[i] = smallest possible tail of an increasing subsequence of length i+1
    for x in lst:
        i = bisect.bisect_left(tails, x)   # strict increase → use bisect_left
        if i == len(tails):
            tails.append(x)
        else:
            tails[i] = x
    return len(tails)
